-- 0020 — seed: São Vicente business directory ("phone book"), unclaimed.
-- Compiled from public sources on 2026-07-22. Every row is seeded (user_id null),
-- published, and carries its primary source. Owners can claim their profile
-- (migration 0019). Re-runnable: refreshes only still-unclaimed rows, never
-- overwrites a claimed profile. Run AFTER 0019.
-- Official government offices are intentionally excluded (official != commercial).

begin;

-- Professionals (legal, construction, trades, cleaning, gas) -----------------
on conflict (slug) do update set
  display_name = excluded.display_name, headline = excluded.headline, bio = excluded.bio,
  category = excluded.category, phone = excluded.phone, service_areas = excluded.service_areas,
  status = excluded.status, source_name = excluded.source_name, source_url = excluded.source_url,
  sourced_at = excluded.sourced_at
where professionals.user_id is null and professionals.claimed_at is null;

-- Suppliers (materials / hardware / paint) -----------------------------------
on conflict (slug) do update set
  name = excluded.name, category = excluded.category, island = excluded.island,
  description = excluded.description, phone = excluded.phone, status = excluded.status,
  source_name = excluded.source_name, source_url = excluded.source_url, sourced_at = excluded.sourced_at
where suppliers.user_id is null and suppliers.claimed_at is null;

commit;
