  (null, 'despachante-carlos-monteiro-fernandes', 'Despachante Oficial Carlos Monteiro Fernandes', '{"pt":"Despachante oficial (desalfandegamento) em Mindelo","en":"Licensed customs broker in Mindelo","nl":"Beëdigd douaneagent in Mindelo"}'::jsonb, '{"pt":"Despachante oficial (cédula n.º 80, 2012): desalfandegamento e documentação para a alfândega, porto (ENAPOR) e aeroporto de São Vicente. Rua Cristiano Sena Barcelos n.º 27, Mindelo. E-mail: geral@despachanteoficial.cv.","en":"Licensed customs broker (licence no. 80, 2012): customs clearance and trade documentation for São Vicente customs, port (ENAPOR) and airport. Rua Cristiano Sena Barcelos no. 27, Mindelo. Email: geral@despachanteoficial.cv.","nl":"Beëdigd douaneagent (vergunning nr. 80, 2012): inklaring en handelsdocumentatie voor de douane, haven (ENAPOR) en luchthaven van São Vicente. Rua Cristiano Sena Barcelos nr. 27, Mindelo. E-mail: geral@despachanteoficial.cv."}'::jsonb, 'Despachante oficial', '{"São Vicente"}', 'published', '+238 232 58 89', 'Website oficial (despachanteoficial.cv)', 'https://www.despachanteoficial.cv/', '2026-07-22'::date),
  (null, 'armando-cunha-cabo-verde', 'Armando Cunha, Cabo Verde, S.A.', '{"pt":"Construção civil e obras públicas","en":"Civil construction and public works","nl":"Civiele bouw en openbare werken"}'::jsonb, '{"pt":"Empresa de construção civil e obras públicas (desde 2007) com sede em Mindelo e estaleiro na Zona Industrial do Lazareto; alvará de construção válido. Estradas, edifícios e obras marítimas e urbanas. E-mail: geral@armandocunha.cv.","en":"Civil-construction and public-works company (since 2007), HQ in Mindelo with a yard in the Lazareto industrial zone; valid construction licence. Roads, buildings, maritime and urban works. Email: geral@armandocunha.cv.","nl":"Bedrijf voor civiele bouw en openbare werken (sinds 2007), hoofdkantoor in Mindelo met werkplaats op het industrieterrein Lazareto; geldige bouwvergunning. Wegen, gebouwen, maritieme en stedelijke werken. E-mail: geral@armandocunha.cv."}'::jsonb, 'Construção civil', '{"São Vicente"}', 'published', '+238 231 96 77', 'IGOTCI — lista de alvarás válidos (Fev 2025) + website oficial', 'https://armandocunha.cv/contactos/', '2026-07-22'::date),
  (null, 'sina-construcoes', 'SINA Construções, Lda', '{"pt":"Construção civil e obras públicas em Mindelo","en":"Civil construction and public works in Mindelo","nl":"Civiele bouw en openbare werken in Mindelo"}'::jsonb, '{"pt":"Sociedade de Investimentos Nacional — construção civil em Mindelo: edifícios, escolas, estradas, saneamento e reabilitação. Alvará de construção válido (Classe 5). E-mail: sina@sina.cv.","en":"Sociedade de Investimentos Nacional — civil construction in Mindelo: buildings, schools, roads, sanitation and rehabilitation. Valid construction licence (Class 5). Email: sina@sina.cv.","nl":"Sociedade de Investimentos Nacional — civiele bouw in Mindelo: gebouwen, scholen, wegen, sanitatie en renovatie. Geldige bouwvergunning (Klasse 5). E-mail: sina@sina.cv."}'::jsonb, 'Construção civil', '{"São Vicente"}', 'published', '+238 230 05 50', 'IGOTCI — lista de alvarás válidos (Fev 2025) + website oficial', 'https://sina.cv/', '2026-07-22'::date),
  (null, 'sci-spencer-construcoes-mindelo', 'SCI – Spencer Construções & Imobiliária, Lda (Mindelo)', '{"pt":"Construção civil e imobiliária — balcão de Mindelo","en":"Construction & real estate — Mindelo branch","nl":"Bouw & vastgoed — vestiging Mindelo"}'::jsonb, '{"pt":"Construção civil, obras públicas, projeto, blocos e alumínio/ferro (desde 2006). Balcão de São Vicente: Rua Baltazar Lopes da Silva n.º 51 (ao lado da Electra), Mindelo. Alvará válido (Classe 7). E-mail: sci@cvtelecom.cv.","en":"Civil construction, public works, design, blocks and aluminium/iron (since 2006). São Vicente branch: Rua Baltazar Lopes da Silva no. 51 (next to Electra), Mindelo. Valid licence (Class 7). Email: sci@cvtelecom.cv.","nl":"Civiele bouw, openbare werken, ontwerp, blokken en aluminium/ijzer (sinds 2006). Vestiging São Vicente: Rua Baltazar Lopes da Silva nr. 51 (naast Electra), Mindelo. Geldige vergunning (Klasse 7). E-mail: sci@cvtelecom.cv."}'::jsonb, 'Construção civil', '{"São Vicente"}', 'published', '+238 232 56 56', 'IGOTCI — lista de alvarás válidos (Fev 2025) + website oficial', 'http://www.sci.cv/', '2026-07-22'::date),
  (null, 'cmcv-construcoes-metalicas', 'Construções Metálicas de Cabo Verde, Lda (CMCV)', '{"pt":"Serralharia e estruturas metálicas (desde 2000)","en":"Metalwork and steel structures (since 2000)","nl":"Metaalbouw en staalconstructies (sinds 2000)"}'::jsonb, '{"pt":"Fabrico e montagem de estruturas metálicas e serralharia em ferro, inox e alumínio; reparação naval e tratamento de superfícies. Zona Industrial da Ribeira de Julião, São Vicente. Certificação ISO 9001. Orçamentos: orcamentos@cmcvlda.cv.","en":"Fabrication and installation of steel structures and ironwork in iron, stainless steel and aluminium; naval repair and surface treatment. Ribeira de Julião industrial zone, São Vicente. ISO 9001 certified. Quotes: orcamentos@cmcvlda.cv.","nl":"Fabricage en montage van staalconstructies en metaalwerk in ijzer, rvs en aluminium; scheepsreparatie en oppervlaktebehandeling. Industrieterrein Ribeira de Julião, São Vicente. ISO 9001-gecertificeerd. Offertes: orcamentos@cmcvlda.cv."}'::jsonb, 'Serralharia / metalomecânica', '{"São Vicente"}', 'published', '+238 232 44 00', 'IGOTCI + Câmara de Comércio do Barlavento + website oficial', 'https://cmcvlda.cv/', '2026-07-22'::date),
  (null, 'ramos-castellano-arquitectos', 'Ramos Castellano Arquitectos', '{"pt":"Atelier de arquitetura em Mindelo","en":"Architecture studio in Mindelo","nl":"Architectenbureau in Mindelo"}'::jsonb, '{"pt":"Atelier de arquitetura (desde 2005) de Eloisa Ramos e Moreno Castellano, Mindelo. Obras publicadas internacionalmente (CNAD, Terra Lodge, Casa Celestina). Av. 5 de Julho 18. Contacto: info@ramoscastellano.com.","en":"Architecture studio (since 2005) of Eloisa Ramos and Moreno Castellano, Mindelo. Internationally published work (CNAD, Terra Lodge, Casa Celestina). Av. 5 de Julho 18. Contact: info@ramoscastellano.com.","nl":"Architectenbureau (sinds 2005) van Eloisa Ramos en Moreno Castellano, Mindelo. Internationaal gepubliceerd werk (CNAD, Terra Lodge, Casa Celestina). Av. 5 de Julho 18. Contact: info@ramoscastellano.com."}'::jsonb, 'Arquitetura', '{"São Vicente"}', 'published', null, 'Website oficial (ramoscastellano.com)', 'https://ramoscastellano.com/contact/', '2026-07-22'::date),
  (null, 'oficina-de-utopias', 'Oficina de Utopias', '{"pt":"Arquitetura, arte e design em Mindelo","en":"Architecture, art and design in Mindelo","nl":"Architectuur, kunst en design in Mindelo"}'::jsonb, '{"pt":"Atelier (desde 2015) de Ângelo Lopes e Rita Rainho: arquitetura, arte e design. Av. Abílio Duarte n.º 32, Mindelo. Projeto Slat House publicado na ArchDaily (2024). E-mail: oficinadeutopias@gmail.com.","en":"Studio (since 2015) of Ângelo Lopes and Rita Rainho: architecture, art and design. Av. Abílio Duarte no. 32, Mindelo. Slat House project published on ArchDaily (2024). Email: oficinadeutopias@gmail.com.","nl":"Studio (sinds 2015) van Ângelo Lopes en Rita Rainho: architectuur, kunst en design. Av. Abílio Duarte nr. 32, Mindelo. Slat House-project gepubliceerd op ArchDaily (2024). E-mail: oficinadeutopias@gmail.com."}'::jsonb, 'Arquitetura', '{"São Vicente"}', 'published', '+238 981 44 88', 'Website oficial + ArchDaily (2024)', 'https://www.oficinadeutopias.com/en/sobre', '2026-07-22'::date),
  (null, 'soteclima', 'Soteclima, Lda', '{"pt":"Ar condicionado e ventilação em Mindelo","en":"Air conditioning and ventilation in Mindelo","nl":"Airco en ventilatie in Mindelo"}'::jsonb, '{"pt":"Venda, instalação e manutenção de ar condicionado (splits, VRV, chillers), ventilação, extração de fumos e solar térmico. Instalador autorizado General Fujitsu, Daitsu e Sodeca. Chã de Alecrim, Mindelo. E-mail: soteclima@soteclima.cv.","en":"Sale, installation and maintenance of air conditioning (splits, VRV, chillers), ventilation, smoke extraction and solar-thermal. Authorised installer for General Fujitsu, Daitsu and Sodeca. Chã de Alecrim, Mindelo. Email: soteclima@soteclima.cv.","nl":"Verkoop, installatie en onderhoud van airco (splits, VRV, chillers), ventilatie, rookafvoer en zonneboilers. Erkend installateur van General Fujitsu, Daitsu en Sodeca. Chã de Alecrim, Mindelo. E-mail: soteclima@soteclima.cv."}'::jsonb, 'Climatização / AVAC', '{"São Vicente"}', 'published', '+238 353 22 07', 'Website oficial (soteclima.cv)', 'https://soteclima.cv/contactos/', '2026-07-22'::date),
