  (null, 'boavista-limpeza', 'Boavista Limpeza', '{"pt":"Serviço de limpeza em Mindelo","en":"Cleaning service in Mindelo","nl":"Schoonmaakdienst in Mindelo"}'::jsonb, '{"pt":"Serviço de limpeza (e produtos de limpeza), Rua Argélia 81, junto à Praça Nova, Mindelo. Horário seg.–sáb.","en":"Cleaning service (and cleaning products), Rua Argélia 81, next to Praça Nova, Mindelo. Open Mon–Sat.","nl":"Schoonmaakdienst (en schoonmaakproducten), Rua Argélia 81, naast Praça Nova, Mindelo. Open ma–za."}'::jsonb, 'Limpeza', '{"São Vicente"}', 'published', '+238 231 76 77', 'AfricaBizInfo + Cleaners10 (listagens públicas)', 'https://www.africabizinfo.com/pt-CV/boavista-limpeza', '2026-07-22'::date),
  (null, 'enacol-gas-mindelo', 'Enacol, S.A. — gás (Mindelo)', '{"pt":"Gás butano e entrega ao domicílio em Mindelo","en":"Butane gas and home delivery in Mindelo","nl":"Butaangas en thuisbezorging in Mindelo"}'::jsonb, '{"pt":"Empresa nacional de combustíveis, com sede em Mindelo. Venda de gás butano e entrega ao domicílio (linha 430 60 60). Pontos de venda em São Vicente (Ribeira Julião, Madeiralzinho 24h, Monte). E-mail: energia@enacol.cv.","en":"National fuel company, headquartered in Mindelo. Butane-gas sales and home delivery (line 430 60 60). São Vicente sales points (Ribeira Julião, Madeiralzinho 24h, Monte). Email: energia@enacol.cv.","nl":"Nationaal brandstofbedrijf, hoofdkantoor in Mindelo. Verkoop van butaangas en thuisbezorging (lijn 430 60 60). Verkooppunten op São Vicente (Ribeira Julião, Madeiralzinho 24u, Monte). E-mail: energia@enacol.cv."}'::jsonb, 'Gás', '{"São Vicente"}', 'published', '+238 430 60 60', 'Website oficial (enacol.cv)', 'https://www.enacol.cv/contactos-enacol/', '2026-07-22'::date),
  (null, 'vivo-energy-shell-mindelo', 'Vivo Energy Cabo Verde (Shell) — Mindelo', '{"pt":"Gás Shell e combustíveis — sede em Mindelo","en":"Shell gas and fuels — HQ in Mindelo","nl":"Shell-gas en brandstoffen — kantoor in Mindelo"}'::jsonb, '{"pt":"Licenciada da Shell em Cabo Verde, sede em Mindelo (Av. Amílcar Cabral). Gás butano (botija) e entrega ao domicílio Shell Gás; combustíveis e lubrificantes.","en":"Shell licensee in Cape Verde, HQ in Mindelo (Av. Amílcar Cabral). Butane gas (botija) with Shell Gás home delivery; fuels and lubricants.","nl":"Shell-licentiehouder in Kaapverdië, kantoor in Mindelo (Av. Amílcar Cabral). Butaangas (botija) met Shell Gás-thuisbezorging; brandstoffen en smeermiddelen."}'::jsonb, 'Gás', '{"São Vicente"}', 'published', '+238 230 76 00', 'Vivo Energy (site oficial) + Câmara de Comércio do Barlavento', 'https://www.vivoenergy.com/en/contacts', '2026-07-22'::date),
  (null, 'estacao-shell-rua-da-praia', 'Estação Shell Rua da Praia (M. Araújo)', '{"pt":"Estação Shell (gás e combustíveis) na Rua da Praia","en":"Shell station (gas and fuels) on Rua da Praia","nl":"Shell-station (gas en brandstof) aan Rua da Praia"}'::jsonb, '{"pt":"Estação de serviço Shell na Rua da Praia, Mindelo: combustíveis, lubrificantes e gás, com serviços ao veículo. E-mail: shellruadapraia@gmail.com.","en":"Shell service station on Rua da Praia, Mindelo: fuels, lubricants and gas, with vehicle services. Email: shellruadapraia@gmail.com.","nl":"Shell-servicestation aan Rua da Praia, Mindelo: brandstoffen, smeermiddelen en gas, met voertuigservice. E-mail: shellruadapraia@gmail.com."}'::jsonb, 'Gás / combustíveis', '{"São Vicente"}', 'published', '+238 232 30 04', 'Website oficial (shellruadapraia.cv)', 'https://shellruadapraia.cv/contactos-uteis/', '2026-07-22'::date)
